## Complete Example: Paginated Blog Posts

```typescript
interface Post {
    title: string;
    content: string;
    status: 'draft' | 'published';
    views: number;
    tags: string[];
    createdAt: string;
}

async function getPublishedPosts(pageCursor?: string, pageSize = 20) {
    const queries: string[] = [
        Query.equal('status', 'published'),
        Query.orderDesc('createdAt'),
        Query.limit(pageSize),
        Query.select(['title', 'views', 'tags', 'createdAt']),
    ];

    if (pageCursor) {
        queries.push(Query.cursorAfter(pageCursor));
    }

    const result = await tablesDB.listRows({
        databaseId: '[DATABASE_ID]',
        tableId: '[TABLE_ID]',
        queries,
    });

    return {
        posts: result.documents as unknown as Post[],
        total: result.total,
        nextCursor: result.documents.length === pageSize
            ? result.documents[result.documents.length - 1].$id
            : null,
    };
}

// Usage
const { posts, total, nextCursor } = await getPublishedPosts();
console.log(`Showing ${posts.length} of ${total} posts`);
// Pass nextCursor to getPublishedPosts(nextCursor) for the next page
```

