// await getCurrentUser();
// await logout();
```

### Key Notes:
* **`ID.unique()`**: Automatically generates a unique ID for the new user.
* **Session Management**: Once `createEmailPasswordSession` is called, Appwrite automatically stores the session in the browser's local storage/cookies. Subsequent calls to `account.get()` will return the logged-in user.
* **Error Handling**: Always wrap Appwrite calls in a `try/catch` block and check for `AppwriteException` to handle errors like duplicate emails or incorrect passwords gracefully.

Here's the complete code using the current Appwrite Web SDK (`appwrite` package) and the `TablesDB` API:

```typescript
import { Client, TablesDB, ID } from 'appwrite';

// 1. Initialize the Appwrite client
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1') // e.g., https://cloud.appwrite.io/v1
    .setProject('[PROJECT_ID]');

const tablesDB = new TablesDB(client);

async function setupTasksDatabase() {
    try {
        // 2. Create a database
        const database = await tablesDB.create({
            databaseId: ID.unique(),
            name: 'Task Manager DB'
        });
        console.log('Ō£ģ Database created:', database.$id);

        // 3. Create the "tasks" table with columns
        const table = await tablesDB.createTable({
            databaseId: database.$id,
            tableId: 'tasks',
            name: 'Tasks',
            columns: [
                { key: 'title',     type: 'varchar',  size: 255, required: true },
                { key: 'completed', type: 'boolean',  required: true, default: false },
                { key: 'dueDate',   type: 'datetime', required: false }
            ]
        });
        console.log('Ō£ģ Table created:', table.$id);

        // 4. Insert a row
        const newRow = await tablesDB.createRow({
            databaseId: database.$id,
            tableId: 'tasks',
            rowId: ID.unique(),
            data: {
                title: 'Finish Appwrite integration',
                completed: false,
                dueDate: new Date().toISOString() // Appwrite expects ISO 8601 strings for datetime
            }
        });
