        console.error('ŌØī Error setting up database:', error);
    }
}

setupTasksDatabase();
```

### ­¤öæ Important Notes:
1. **Admin Privileges**: `tablesDB.create()` and `tablesDB.createTable()` are **admin-level operations**. In a browser environment, they will fail unless the authenticated user has explicit database/table creation permissions, or you're using an API key (which is **not recommended** for client-side code). Typically, databases and tables are created once via the Appwrite Console, CLI, or a secure backend.
2. **Column Types**: 
   - `varchar` requires a `size` (max 16,383). `255` is standard for titles.
   - `datetime` columns store ISO 8601 strings. Always pass `new Date().toISOString()` or a valid ISO string.
3. **Row Permissions**: By default, newly created rows have **no permissions**. If you want users to read/update them, pass a `permissions` array to `createRow()` using `Permission` and `Role` helpers.

In Appwrite, you query rows using the `Query` class, which is passed as an array to the `queries` parameter of the `listRows` method.

### Basic Setup
```typescript
import { Client, TablesDB, Query } from 'appwrite'; // or 'node-appwrite'

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const tablesDB = new TablesDB(client);
```

### 1. Filtering
Filter rows based on column values. Multiple filters are combined with an implicit `AND`.

```typescript
const results = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        // Exact match (or pass an array for IN queries)
        Query.equal('status', 'active'),

        // Numeric comparisons
        Query.greaterThan('age', 18),
        Query.lessThanEqual('price', 100),
        Query.between('rating', 4, 5),

        // Null checks
        Query.isNull('deletedAt'),

        // String matching
        Query.startsWith('email', 'admin@'),
        Query.contains('tags', 'featured'),

        // Full-text search (requires a full-text index on the column)
        Query.search('content', 'Appwrite tutorial'),
    ]
});
```

### 2. Sorting
Sort results by one or more columns.

```typescript
const results = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.orderDesc('$createdAt'), // Newest first
        Query.orderAsc('title'),       // Then alphabetically by title
    ]
});
```

### 3. Limiting
Control the maximum number of rows returned. The default is 25, and the maximum is 100.

```typescript
const results = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.limit(10) // Return only 10 rows
    ]
});
```

### 4. Pagination
Appwrite supports two pagination methods:

**Offset-based (Traditional)**
Skip a number of rows. Best for small datasets.
```typescript
const page2 = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.limit(25),
        Query.offset(25) // Skip the first 25 rows
    ]
});
```

**Cursor-based (Recommended for large datasets)**
Use the `$id` of the last row from the previous page to fetch the next page. This is much faster and avoids performance issues with large offsets.
```typescript
// Page 1
const page1 = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [Query.limit(25)]
});

const lastRowId = page1.documents[page1.documents.length - 1].$id;

// Page 2
const page2 = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.limit(25),
        Query.cursorAfter(lastRowId) // Fetch rows after this ID
    ]
});
```

### 5. Logical Operators & Selection
**Logical Operators:**
```typescript
// OR condition
Query.or([
    Query.equal('status', 'active'),
    Query.equal('status', 'pending')
])

// Explicit AND (usually unnecessary as queries are AND by default)
Query.and([
    Query.greaterThan('age', 18),
    Query.equal('country', 'US')
])
```

**Field Selection:**
Return only specific fields to reduce payload size.
```typescript
Query.select(['title', 'status', '$id'])
```

### Complete Example
Combining filtering, sorting, limiting, and cursor pagination:

```typescript
const results = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.equal('category', 'electronics'),
        Query.greaterThan('price', 50),
        Query.orderDesc('price'),
        Query.limit(20),
        Query.cursorAfter('[LAST_ROW_ID_FROM_PREVIOUS_PAGE]')
    ]
});

console.log(`Total matching rows: ${results.total}`);
results.documents.forEach(doc => {
    console.log(doc.title, doc.price);
});
```

To filter rows where a numeric field is greater than 100, limit the results to 20, and sort them by that field in descending order, you can combine `Query.greaterThan`, `Query.orderDesc`, and `Query.limit` in your `listRows` call.

Here's an example using the TypeScript SDK:

```typescript
import { Client, TablesDB, Query } from 'appwrite'; // or 'node-appwrite' for server-side

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const tablesDB = new TablesDB(client);

const results = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.greaterThan('score', 100), // Filter: score > 100
        Query.orderDesc('score'),        // Sort: highest score first
        Query.limit(20)                  // Limit: max 20 results
    ]
});

console.log(results.documents);
```

### Breakdown of the Query Methods:
* **`Query.greaterThan('score', 100)`**: Filters the rows to only include those where the `score` field is strictly greater than 100.
* **`Query.orderDesc('score')`**: Sorts the filtered results by the `score` field in descending order (highest to lowest).
* **`Query.limit(20)`**: Restricts the number of returned rows to a maximum of 20.

Here's the complete Appwrite Function for Node.js:

```javascript
export default async (req, res) => {
  try {
    // Appwrite automatically parses JSON bodies, so req.body is ready to use
    const { name } = req.body;

    if (!name) {
      return res.status(400).json({ error: "Missing 'name' field in request body" });
    }

    return res.json({ greeting: `Hello, ${name}!` });
  } catch (error) {
    return res.status(500).json({ error: error.message });
  }
};
```

### Key Details:
- **Function Signature**: `export default async (req, res) => { ... }` is the required entry point for Appwrite Node.js functions.
- **Request Object (`req`)**: `req.body` is automatically parsed by Appwrite when the request includes `Content-Type: application/json`.
- **Response Object (`res`)**: Use `res.json()` to return JSON responses. Chain `.status(code)` to set HTTP status codes.
- **Runtime**: Deploy with the `node-18` or `node-20` runtime in Appwrite.
- **Testing**: You can trigger this function via the Appwrite Dashboard, CLI (`appwrite functions createExecution`), or by making a `POST` request to the function's execution endpoint with a JSON body like `{"name": "Alice"}`.

Here's a complete example using the Appwrite Web SDK. Note that **bucket creation is an admin operation** and is typically done via the Appwrite Console or server-side SDK. I'll show the client-side file upload with permissions and preview URL generation, plus the server-side bucket creation for completeness.

## 1. Setup & Bucket Creation

### Client Setup (Web)
```typescript
import { Client, Storage, ID, Permission, Role } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // or your self-hosted endpoint
    .setProject('[PROJECT_ID]');

const storage = new Storage(client);
```

### Create Bucket (Server-Side Only)
Bucket creation requires an API key and must be done server-side:
```typescript
import { Client, Storage } from 'node-appwrite';

const serverClient = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]')
    .setKey('[API_KEY]');

const serverStorage = new Storage(serverClient);

const bucket = await serverStorage.createBucket({
    bucketId: 'my-images',
    name: 'My Images',
    enabled: true,
    maximumFileSize: 5242880, // 5MB
    allowedFileExtensions: ['jpg', 'jpeg', 'png', 'gif', 'webp'],
    encryption: true,
    antivirus: true,
    permissions: [
        Permission.read(Role.any()),           // Anyone can read files
        Permission.create(Role.users()),       // Authenticated users can upload
        Permission.update(Role.users()),       // Authenticated users can update
        Permission.delete(Role.users()),       // Authenticated users can delete
    ]
});
```

## 2. Upload File with Permissions (Client-Side)

```typescript
async function uploadImage(fileInput: HTMLInputElement) {
    const file = fileInput.files?.[0];
    if (!file) throw new Error('No file selected');

    try {
        const uploadedFile = await storage.createFile({
            bucketId: 'my-images',
            fileId: ID.unique(),
            file: file,
            permissions: [
                Permission.read(Role.any()),              // Public read access
                Permission.update(Role.user('[USER_ID]')), // Only owner can update
                Permission.delete(Role.user('[USER_ID]')), // Only owner can delete
            ]
        });

        console.log('File uploaded:', uploadedFile);
        return uploadedFile;
    } catch (error) {
        console.error('Upload failed:', error);
        throw error;
    }
}

// Usage with HTML:
// <input type="file" id="file-input" accept="image/*" />
// <button onclick="uploadImage(document.getElementById('file-input'))">Upload</button>
```

## 3. Get Preview URL

```typescript
function getImagePreviewUrl(bucketId: string, fileId: string) {
    // getFilePreview returns a URL string, not a Promise
    const previewUrl = storage.getFilePreview({
        bucketId: bucketId,
        fileId: fileId,
        width: 400,
        height: 300,
        gravity: 'center',    // Crop gravity: center, top, bottom, left, right
        quality: 90,          // Image quality (1-100)
        borderWidth: 0,       // Optional border
        borderColor: '',      // Optional border color (hex)
        borderRadius: 0,      // Optional border radius
        opacity: 1,           // Image opacity (0-1)
        rotation: 0,          // Rotation in degrees
        background: '',       // Background color for transparent images (hex)
        output: 'jpg'         // Output format: jpg, png, webp
    });

    return previewUrl;
}

// Usage:
// const previewUrl = getImagePreviewUrl('my-images', uploadedFile.$id);
// document.getElementById('preview').src = previewUrl;
```

## 4. Complete Example

```typescript
import { Client, Storage, ID, Permission, Role } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const storage = new Storage(client);

async function handleImageUpload(fileInput: HTMLInputElement, previewImg: HTMLImageElement) {
    const file = fileInput.files?.[0];
    if (!file) return;

    try {
        // Upload with permissions
        const uploadedFile = await storage.createFile({
            bucketId: 'my-images',
            fileId: ID.unique(),
            file: file,
            permissions: [
                Permission.read(Role.any()),
                Permission.update(Role.user('[USER_ID]')),
                Permission.delete(Role.user('[USER_ID]')),
            ]
        });

        // Get preview URL
        const previewUrl = storage.getFilePreview({
            bucketId: 'my-images',
            fileId: uploadedFile.$id,
            width: 400,
            height: 300,
            quality: 90
        });

        // Display preview
        previewImg.src = previewUrl;
        console.log('Upload successful:', uploadedFile.$id);
    } catch (error) {
        console.error('Upload failed:', error);
    }
}
```

## Key Notes

- **Bucket creation** requires server-side SDK with API key or must be done in the Appwrite Console
- **Permissions** are set at the file level here. If all files in a bucket share the same rules, configure them at the bucket level instead and omit file-level permissions
- **`getFilePreview()`** returns a URL string synchronously (no `await` needed)
- **`Role.any()`** makes files publicly readable. Use `Role.users()` or `Role.user('[USER_ID]')` for authenticated-only access
- Preview URLs support image transformations (resize, crop, format conversion, quality adjustment)

# Appwrite Messaging: Push Notifications

Appwrite Messaging provides a unified API for sending push notifications, emails, and SMS. Here's how to set up and use push notifications.

## Supported Providers

Appwrite Messaging supports two push notification providers:

| Provider | Platform | Description |
|----------|----------|-------------|
| **APNs** (Apple Push Notification service) | iOS, macOS, watchOS, tvOS | Requires an APNs Key (`.p8` file) and Team ID from your Apple Developer account |
| **FCM** (Firebase Cloud Messaging) | Android, Web, iOS (alternative) | Requires a Firebase project and server key or service account credentials |

You can configure both providers simultaneously in the Appwrite Console under **Messaging ŌåÆ Providers**.

## Setup Steps

### 1. Enable Messaging Service
In the Appwrite Console, go to **Settings ŌåÆ Services** and enable **Messaging**.

### 2. Configure Push Providers
- **APNs**: Upload your `.p8` key file, provide your Team ID, Key ID, and Bundle ID.
- **FCM**: Provide your Firebase project credentials (server key or service account JSON).

### 3. Create a Topic
Topics are channels that users can subscribe to. You can create them via the Console, CLI, or SDK:

```bash
# CLI
appwrite messaging create-topic \
    --topic-id "news-updates" \
    --name "News Updates"
```

```typescript
// TypeScript SDK (server-side)
import { Client, Messaging } from 'node-appwrite';

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]')
    .setKey(process.env.APPWRITE_API_KEY);

const messaging = new Messaging(client);

const topic = await messaging.createTopic({
    topicId: 'news-updates',
    name: 'News Updates',
});
```

### 4. Add Subscribers to a Topic
Users (or targets) subscribe to topics to receive messages:

```bash
# CLI
appwrite messaging create-subscriber \
    --topic-id "news-updates" \
    --subscriber-id "unique()" \
    --target-id "[TARGET_ID]"
```

```typescript
// TypeScript SDK
await messaging.createSubscriber({
    topicId: 'news-updates',
    subscriberId: ID.unique(),
    targetId: '[TARGET_ID]',  // A push target (device token) ID
});
```

> **Note:** A **target** represents a specific device/app instance. You create targets by registering device tokens (APNs device token or FCM registration token) with Appwrite.

### 5. Send a Push Notification to a Topic

```bash
# CLI
appwrite messaging create-push \
    --message-id "unique()" \
    --title "Breaking News" \
    --body "Check out the latest updates!" \
    --topics '["news-updates"]'
```

```typescript
// TypeScript SDK
const message = await messaging.createPush({
    messageId: ID.unique(),
    title: 'Breaking News',
    body: 'Check out the latest updates!',
    topics: ['news-updates'],
    // Optional: target specific platforms
    // android: { title: '...', body: '...', ... },
    // ios: { title: '...', body: '...', ... },
});
```

## Full Example: End-to-End Flow

```typescript
import { Client, Messaging, ID } from 'node-appwrite';

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]')
    .setKey(process.env.APPWRITE_API_KEY);

const messaging = new Messaging(client);

// 1. Create a topic
await messaging.createTopic({
    topicId: 'product-launches',
    name: 'Product Launches',
});

// 2. Register a device target (FCM example)
const target = await messaging.createTarget({
    targetId: ID.unique(),
    identifier: 'fcm_device_token_here',  // FCM registration token
    providerId: '[FCM_PROVIDER_ID]',       // Your configured FCM provider ID
    userId: '[USER_ID]',
});

// 3. Subscribe the target to the topic
await messaging.createSubscriber({
    topicId: 'product-launches',
    subscriberId: ID.unique(),
    targetId: target.$id,
});

// 4. Send push notification to all topic subscribers
await messaging.createPush({
    messageId: ID.unique(),
    title: 'New Product Launch! ­¤ÜĆ',
    body: 'We just launched something amazing. Tap to learn more.',
    topics: ['product-launches'],
    // Platform-specific overrides (optional)
    android: {
        title: 'New Product Launch!',
        body: 'We just launched something amazing.',
        icon: 'ic_notification',
    },
    ios: {
        title: 'New Product Launch!',
        body: 'We just launched something amazing.',
        badge: 1,
        sound: 'default',
    },
});
```

## Key Concepts

| Concept | Description |
|---------|-------------|
| **Provider** | The push service (APNs or FCM) configured with credentials |
| **Target** | A registered device (identified by its APNs token or FCM registration token) |
| **Topic** | A named channel that targets subscribe to |
| **Subscriber** | The link between a target and a topic |
| **Message** | The push notification payload sent to topic subscribers |

## Client-Side: Registering Device Tokens

On the client side (mobile/web app), you need to obtain the device token from the platform's push service and register it as a target in Appwrite:

```typescript
// Client-side (React Native example with FCM)
import { Client, Messaging, ID } from 'react-native-appwrite';
import messaging from '@react-native-firebase/messaging';

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

// Get FCM token
const fcmToken = await messaging().getToken();

// Register as Appwrite target (requires authenticated session)
const appwriteMessaging = new Messaging(client);
await appwriteMessaging.createTarget({
    targetId: ID.unique(),
    identifier: fcmToken,
    providerId: '[FCM_PROVIDER_ID]',
});
```

This covers the full lifecycle: configure providers ŌåÆ create topics ŌåÆ register device targets ŌåÆ subscribe targets to topics ŌåÆ send push messages to topics.

Here's how to subscribe to both table row changes and file uploads simultaneously, handling each event type differently:

```typescript
import { Client, Realtime, Channel } from 'appwrite';

// 1. Initialize the client
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

// 2. Create Realtime instance
const realtime = new Realtime(client);

// 3. Subscribe to multiple channels at once
const subscription = await realtime.subscribe(
    [
        Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row(),
        Channel.bucket('[BUCKET_ID]').file(),
    ],
    (response) => {
        // 4. Handle each event type differently
        const event = response.events[0]; // Primary event string

        if (event.includes('tablesdb')) {
            handleTableRowChange(response);
        } else if (event.includes('buckets')) {
            handleFileUpload(response);
        }
    }
);

// Handler for table row changes
function handleTableRowChange(response: any) {
    const event = response.events[0];
    const row = response.payload;

    if (event.endsWith('.create')) {
        console.log('­¤ōØ New row created:', row);
        // e.g., add to UI list, show notification
    } else if (event.endsWith('.update')) {
        console.log('Ō£Å’ĖÅ Row updated:', row);
        // e.g., update existing UI element
    } else if (event.endsWith('.delete')) {
        console.log('­¤Śæ’ĖÅ Row deleted:', row.$id);
        // e.g., remove from UI list
    }
}

// Handler for file uploads
function handleFileUpload(response: any) {
    const event = response.events[0];
    const file = response.payload;

    if (event.endsWith('.create')) {
        console.log('­¤ōü New file uploaded:', file.name);
        console.log('  Size:', file.sizeOriginal, 'bytes');
        console.log('  MIME:', file.mimeType);
        // e.g., show upload notification, add to gallery
    } else if (event.endsWith('.update')) {
        console.log('­¤öä File updated:', file.name);
    } else if (event.endsWith('.delete')) {
        console.log('­¤Śæ’ĖÅ File deleted:', file.name);
    }
}

// To unsubscribe later:
// await subscription.close();
```

### Key Points

- **Multiple channels**: Pass an array of channels to `subscribe()` to listen to multiple resources with a single callback
- **Event detection**: Use `response.events[0]` to determine the event type. Event strings follow patterns like:
  - `tablesdb.*.tables.*.rows.*.create`
  - `buckets.*.files.*.create`
- **Payload shape**: The `response.payload` contains the full resource object (row data or file metadata)
- **Response object** also includes:
  - `channels` ŌĆö which channels matched this event
  - `timestamp` ŌĆö ISO 8601 timestamp of the event

To listen to both a TablesDB table's rows and a storage bucket's files in a single call, pass an array of channels to `realtime.subscribe()`:

```typescript
import { Realtime, Channel } from 'appwrite';

const realtime = new Realtime(client);

const subscription = await realtime.subscribe([
    Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row(),
    Channel.bucket('[BUCKET_ID]').file(),
], (response) => {
    console.log('Event:', response.events);
    console.log('Payload:', response.payload);
});
```

### Exact Channel Strings
| Channel Builder | Exact String |
|-----------------|--------------|
| `Channel.tablesdb('[DATABASE_ID]').table('[TABLE_ID]').row()` | `tablesdb.[DATABASE_ID].tables.[TABLE_ID].rows` |
| `Channel.bucket('[BUCKET_ID]').file()` | `buckets.[BUCKET_ID].files` |

*(Replace `[DATABASE_ID]`, `[TABLE_ID]`, and `[BUCKET_ID]` with your actual resource IDs.)*

# Client-Side vs Server-Side SDKs in Appwrite

## Overview

Appwrite provides different SDK packages optimized for different runtime environments. The choice between them depends primarily on **where your code runs** and **what level of access you need**.

| Aspect | Client-Side SDK | Server-Side SDK |
|--------|-----------------|-----------------|
| **Package** | `appwrite` (web) / `react-native-appwrite` (mobile) | `node-appwrite` (Node.js/Deno) |
| **Authentication** | Session-based (user login) | API key-based (admin access) |
| **Runs in** | Browser, React Native apps | Server, serverless functions, CLI tools |
| **Security** | No secrets exposed to client | API key must stay server-side |

---

## Client-Side SDK

**Package:** `npm install appwrite` (web) or `npm install react-native-appwrite` (mobile)

```typescript
import { Client, Account, TablesDB, Storage } from 'appwrite';

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');
```

### When to Use Client-Side SDK

- **Browser-based web apps** ŌĆö React, Vue, Angular, vanilla JS
- **React Native mobile apps** ŌĆö iOS/Android apps built with React Native
- **Any code that runs on user's device**

### Key Capabilities

| Feature | Available |
|---------|-----------|
| User signup/login (email, OAuth) | Ō£ģ |
| Real-time subscriptions | Ō£ģ |
| File uploads from browser/file input | Ō£ģ |
| Read/write user data | Ō£ģ |
| Query databases | Ō£ģ |
| Create databases/tables/users | ŌØī |
| Admin operations | ŌØī |

### Example: User Authentication

```typescript
const account = new Account(client);

// Email/password login
const session = await account.createEmailPasswordSession({
    email: 'user@example.com',
    password: 'password123'
});

// OAuth login (web)
account.createOAuth2Session({
    provider: OAuthProvider.Github,
    success: 'https://example.com/success',
    failure: 'https://example.com/fail'
});

// Get current user
const user = await account.get();
```

### Example: Real-time Subscriptions

```typescript
import { Realtime, Channel } from 'appwrite';

const realtime = new Realtime(client);

await realtime.subscribe(
    Channel.tablesdb('[DB_ID]').table('[TABLE_ID]').row(),
    (response) => {
        console.log(response.events);
        console.log(response.payload);
    }
);
```

---

## Server-Side SDK

**Package:** `npm install node-appwrite`

```typescript
import { Client, Users, TablesDB, Storage } from 'node-appwrite';

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject(process.env.APPWRITE_PROJECT_ID)
    .setKey(process.env.APPWRITE_API_KEY);  // API key for admin access
```

### When to Use Server-Side SDK

- **Backend servers** ŌĆö Node.js/Deno APIs
- **Serverless functions** ŌĆö Appwrite Functions, AWS Lambda, etc.
- **Server-side rendering (SSR)** ŌĆö Next.js, SvelteKit, Remix
- **CLI tools and scripts** ŌĆö Automated admin tasks
- **Any code that must not expose secrets to users**

### Key Capabilities

| Feature | Available |
|---------|-----------|
| All client-side operations | Ō£ģ |
| Create/update/delete databases & tables | Ō£ģ |
| User management (create, list, delete users) | Ō£ģ |
| File uploads from filesystem | Ō£ģ |
| Execute Appwrite Functions | Ō£ģ |
| Bypass rate limits | Ō£ģ |
| Admin operations | Ō£ģ |

### Example: User Management

```typescript
const users = new Users(client);

// Create user
const user = await users.create({
    userId: ID.unique(),
    email: 'user@example.com',
    password: 'password123',
    name: 'User Name'
});

// List all users
const list = await users.list({ queries: [Query.limit(25)] });

// Delete user
await users.delete({ userId: '[USER_ID]' });
```

### Example: File Upload from Filesystem

```typescript
import { InputFile } from 'node-appwrite/file';

const file = await storage.createFile({
    bucketId: '[BUCKET_ID]',
    fileId: ID.unique(),
    file: InputFile.fromPath('/path/to/file.png', 'file.png')
});
```

---

## Server-Side Rendering (SSR) Pattern

SSR apps need **both** SDKs working together:

```typescript
import { Client, Account, OAuthProvider } from 'node-appwrite';

// Admin client ŌĆö reusable, uses API key
const adminClient = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]')
    .setKey(process.env.APPWRITE_API_KEY);

// Session client ŌĆö per-request, uses session cookie
const sessionClient = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const session = req.cookies['a_session_[PROJECT_ID]'];
if (session) {
    sessionClient.setSession(session);
}
```

---

## Quick Decision Guide

```
Is your code running on a user's device (browser/mobile)?
Ōö£ŌöĆŌöĆ YES ŌåÆ Use Client-Side SDK
Ōöé         ŌĆó appwrite (web)
Ōöé         ŌĆó react-native-appwrite (React Native)
Ōöé
ŌööŌöĆŌöĆ NO ŌåÆ Use Server-Side SDK
          ŌĆó node-appwrite (Node.js/Deno)
          ŌĆó Required for: creating databases, user management,
            admin operations, or any code that needs API keys
```

---

## Security Warning

> ŌÜĀ’ĖÅ **Never expose API keys in client-side code.** The server-side SDK uses `.setKey()` to authenticate with an API key. If this key is included in client-side code, malicious users can extract it and gain full admin access to your Appwrite project.

Client-side SDKs intentionally do **not** include API key methods ŌĆö they use session-based authentication where users log in and receive a session token.

Here's the complete implementation for email/password signup and login using the Appwrite Web SDK:

## Installation

```bash
npm install appwrite
```

## Complete Implementation

```typescript
import { Client, Account, ID } from 'appwrite';

// 1. Set up the client
const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

// Initialize the Account service
const account = new Account(client);

// 2. Sign up - Create a new account
async function signup(email: string, password: string, name: string) {
    try {
        const user = await account.create({
            userId: ID.unique(),
            email: email,
            password: password,
            name: name
        });
        console.log('Account created:', user);
        return user;
    } catch (error) {
        console.error('Signup failed:', error);
        throw error;
    }
}

// 3. Log in - Create a session
async function login(email: string, password: string) {
    try {
        const session = await account.createEmailPasswordSession({
            email: email,
            password: password
        });
        console.log('Session created:', session);
        return session;
    } catch (error) {
        console.error('Login failed:', error);
        throw error;
    }
}

// 4. Get the currently authenticated user
async function getCurrentUser() {
    try {
        const user = await account.get();
        console.log('Current user:', user);
        return user;
    } catch (error) {
        console.error('No active session:', error);
        return null;
    }
}

// 5. Log out - Delete the current session
async function logout() {
    try {
        await account.deleteSession({ sessionId: 'current' });
        console.log('Logged out successfully');
    } catch (error) {
        console.error('Logout failed:', error);
        throw error;
    }
}

// Example usage
async function main() {
    // Sign up a new user
    await signup('user@example.com', 'password123', 'John Doe');

    // Log in the user
    await login('user@example.com', 'password123');

    // Check if user is logged in
    const user = await getCurrentUser();
    if (user) {
        console.log('User is authenticated:', user.name);
    }

    // Log out when done
    await logout();
}

main();
```

## Key Points

| Method | Purpose |
|--------|---------|
| `account.create()` | Registers a new user account |
| `account.createEmailPasswordSession()` | Creates a session for an existing user (login) |
| `account.get()` | Retrieves the currently authenticated user |
| `account.deleteSession()` | Logs out the current user |

## Notes

- **Signup vs Login**: `create()` registers a new account, while `createEmailPasswordSession()` logs in an existing user. You can combine them by calling login immediately after signup.
- **Session persistence**: The SDK automatically stores the session cookie in the browser. Subsequent API calls will include it.
- **Error handling**: Wrap calls in try/catch blocks to handle cases like duplicate emails (409) or invalid credentials (401).
- **Password requirements**: Appwrite requires passwords to be at least 8 characters with lowercase, uppercase, and number characters.

# Appwrite Sessions: Creation, Management, and Deletion

## Overview

Appwrite sessions are the core mechanism for maintaining user authentication state. When a user logs in, Appwrite creates a session that tracks their authenticated state across requests.

---

## Session Creation

### 1. Email/Password Login (Client-side)
```typescript
const account = new Account(client);
const session = await account.createEmailPasswordSession({
    email: 'user@example.com',
    password: 'password123'
});
```
The `session` object returned contains:
- `secret` ŌĆö the session token
- `expire` ŌĆö expiration timestamp
- `userId` ŌĆö the authenticated user's ID

### 2. OAuth 2 Login (Web)
```typescript
account.createOAuth2Session({
    provider: OAuthProvider.Github,
    success: 'https://example.com/success',
    failure: 'https://example.com/fail',
});
```
This redirects to the OAuth provider, then back to your app with credentials that automatically create a session.

### 3. OAuth 2 Login (React Native)
```typescript
// Step 1: Get OAuth URL
const loginUrl = await account.createOAuth2Token({
    provider: OAuthProvider.Github,
    success: `${deepLink}`,
    failure: `${deepLink}`,
});

// Step 2: Open browser, handle redirect, extract credentials
// ...

// Step 3: Create session
await account.createSession({ userId, secret });
```

### 4. Server-Side (SSR)
Sessions are created using the **admin client** and stored in cookies:

```typescript
const account = new Account(adminClient);
const session = await account.createEmailPasswordSession({
    email, password
});

// Cookie name must be: a_session_<PROJECT_ID>
res.cookie('a_session_[PROJECT_ID]', session.secret, {
    httpOnly: true,
    secure: true,
    sameSite: 'strict',
    expires: new Date(session.expire),
    path: '/',
});
```

---

## Session Management

### Getting the Current User
```typescript
// Client-side (uses active session automatically)
const user = await account.get();

// SSR (requires session client per request)
const sessionClient = new Client()
    .setEndpoint('...')
    .setProject('[PROJECT_ID]')
    .setSession(req.cookies['a_session_[PROJECT_ID]']);

const account = new Account(sessionClient);
const user = await account.get();
```

### Listing Active Sessions
```typescript
const sessions = await account.listSessions();
sessions.sessions.forEach(session => {
    console.log(session.$id);        // session ID
    console.log(session.country);    // user's country
    console.log(session.device);     // device info
    console.log(session.ip);         // IP address
});
```

### Switching Sessions
To switch from one session to another:
```typescript
// Get all sessions
const sessions = await account.listSessions();

// Switch to a specific session
client.setSession(sessions.sessions[0].secret);
```

---

## Session Deletion

### Delete a Specific Session
```typescript
await account.deleteSession({ sessionId: '[SESSION_ID]' });
```

### Delete the Current Session
```typescript
await account.deleteSession({ sessionId: 'current' });
```

### Delete All Sessions for a User (Server-side)
```typescript
const users = new Users(adminClient);
await users.deleteSessions({ userId: '[USER_ID]' });
```

---

## Session Limits

Based on Appwrite's default behavior:

| Limit Type | Default Value |
|------------|---------------|
| Sessions per user | ~10-15 (varies by plan) |
| Session duration | Configurable (default: ~1 year) |
| Concurrent sessions per device | Varies |

**Key points about session limits:**

1. **Per-user session limit** ŌĆö Appwrite limits how many active sessions a single user can have. When the limit is reached, the oldest sessions are automatically invalidated.

2. **Configurable expiration** ŌĆö Session duration can be configured in your Appwrite project's authentication settings.

3. **Automatic cleanup** ŌĆö Expired sessions are automatically cleaned up by Appwrite.

4. **Device-based tracking** ŌĆö Sessions store metadata including device type, IP address, country, and browser, allowing users to review and revoke sessions from suspicious locations.

### Checking Session Limits

You can view all active sessions for a user via `listSessions()` to monitor usage:

```typescript
const sessions = await account.listSessions();
console.log(`Active sessions: ${sessions.sessions.length}`);
```

---

## Security Best Practices

1. **Use `httpOnly` cookies** ŌĆö Prevents XSS attacks from accessing the session token
2. **Use `secure: true`** ŌĆö Ensures cookies are only sent over HTTPS
3. **Use `sameSite: 'strict'`** ŌĆö Prevents CSRF attacks
4. **Forward user agent** (SSR):
   ```typescript
   sessionClient.setForwardedUserAgent(req.headers['user-agent']);
   ```
5. **Create a fresh session client per request** ŌĆö Never share session clients between users

---

## Summary

| Operation | Method |
|-----------|--------|
| Create session | `createEmailPasswordSession()`, `createOAuth2Session()`, `createSession()` |
| Get current user | `account.get()` |
| List all sessions | `account.listSessions()` |
| Delete current session | `account.deleteSession({ sessionId: 'current' })` |
| Delete all user sessions | `users.deleteSessions({ userId })` (server-side) |

Sessions are the bridge between authentication and authorization in AppwriteŌĆöonce created, they authenticate every subsequent API request made with that client.

Here's the code to create a database, table with columns, and insert a row using the Appwrite Web SDK's `TablesDB` API:

> **Note:** Creating databases and tables requires server-side execution with an API key. Client-side code can only perform row operations. I'll include both examples.

## Server-Side (Node.js / Deno)

```typescript
import { Client, TablesDB, ID } from 'node-appwrite';

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]')
    .setKey('[API_KEY]'); // Server-side only

const tablesDB = new TablesDB(client);

async function setupDatabase() {
    // 1. Create database
    const database = await tablesDB.create({
        databaseId: ID.unique(),
        name: 'my_tasks_db',
    });
    console.log('Database created:', database.$id);

    // 2. Create table with columns
    const table = await tablesDB.createTable({
        databaseId: database.$id,
        tableId: ID.unique(),
        name: 'tasks',
        columns: [
            { key: 'title',     type: 'varchar',   size: 255, required: true  },
            { key: 'completed', type: 'boolean',                      required: false },
            { key: 'dueDate',   type: 'datetime',                     required: false },
        ],
    });
    console.log('Table created:', table.$id);

    // 3. Insert a row
    const row = await tablesDB.createRow({
        databaseId: database.$id,
        tableId: table.$id,
        rowId: ID.unique(),
        data: {
            title: 'Finish Appwrite tutorial',
            completed: false,
            dueDate: '2025-02-15T10:00:00Z',
        },
    });
    console.log('Row created:', row.$id);
    console.log('Row data:', row);
}

setupDatabase();
```

## Client-Side (Web Browser)

Client-side can only perform row operationsŌĆöyou must create the database and table server-side first:

```typescript
import { Client, TablesDB, ID } from 'appwrite';

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const tablesDB = new TablesDB(client);

// Insert a row (database and table must already exist server-side)
const row = await tablesDB.createRow({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    rowId: ID.unique(),
    data: {
        title: 'Finish Appwrite tutorial',
        completed: false,
        dueDate: '2025-02-15T10:00:00Z',
    },
});

console.log('Row created:', row.$id);
console.log('Title:', row.title);
console.log('Completed:', row.completed);
console.log('DueDate:', row.dueDate);
```

## Key Points

| Operation | Location | Why |
|-----------|----------|-----|
| Create database | Server-side (API key) | Prevents abuse of project resources |
| Create table | Server-side (API key) | Controls schema evolution |
| Create/read/update/delete row | Client-side **or** server-side | Users should be able to write data |

The `ID.unique()` helper generates unique IDs for resources. Use a specific string ID if you need a predictable identifier.

# Querying Rows in Appwrite TablesDB

The `Query` class provides a powerful, chainable API for filtering, sorting, limiting, and paginating rows in Appwrite TablesDB.

## Setup

```typescript
import { Client, TablesDB, Query } from 'appwrite'; // or 'node-appwrite' / 'react-native-appwrite'

const client = new Client()
    .setEndpoint('https://<REGION>.cloud.appwrite.io/v1')
    .setProject('[PROJECT_ID]');

const tablesDB = new TablesDB(client);
```

---

## Filtering

Use query methods to filter rows by column values:

```typescript
// Exact match
Query.equal('status', 'active')

// Not equal
Query.notEqual('status', 'archived')

// Numeric comparisons
Query.lessThan('age', 18)
Query.lessThanEqual('price', 100)
Query.greaterThan('stock', 0)
Query.greaterThanEqual('rating', 4)

// Range (inclusive on both ends)
Query.between('price', 10, 50)

// Null checks
Query.isNull('deletedAt')
Query.isNotNull('publishedAt')

// String operations
Query.startsWith('title', 'The')
Query.endsWith('email', '@example.com')
Query.contains('tags', 'featured')

// Full-text search (requires full-text index on the column)
Query.search('description', 'coffee shop')
```

### Combining Filters

Queries are **AND** by default. Use `Query.and()` for explicit grouping or `Query.or()` for OR logic:

```typescript
// AND (default behavior ŌĆö all conditions must match)
const results = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.equal('status', 'active'),
        Query.greaterThan('price', 0),
        Query.startsWith('title', 'A')
    ]
});

// OR (at least one condition must match)
const orResults = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.or([
            Query.equal('category', 'electronics'),
            Query.equal('category', 'books')
        ])
    ]
});

// Nested AND + OR
const complexResults = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.and([
            Query.equal('status', 'active'),
            Query.or([
                Query.equal('type', 'sale'),
                Query.equal('type', 'auction')
            ])
        ])
    ]
});
```

---

## Sorting

Control the order of results:

```typescript
// Sort ascending
Query.orderAsc('createdAt')

// Sort descending
Query.orderDesc('title')

// Multiple sort fields (evaluated left to right)
const sorted = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        Query.orderDesc('priority'),
        Query.orderAsc('title')
    ]
});
```

---

## Limiting

Restrict the number of results returned:

```typescript
// Limit to 10 rows (default is 25, max is 100)
const limited = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [Query.limit(10)]
});
```

---

## Pagination

### Offset-based (simple)

Use `limit` with `offset` to page through results:

```typescript
// Page 1
const page1 = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [Query.limit(10), Query.offset(0)]
});

// Page 2
const page2 = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [Query.limit(10), Query.offset(10)]
});

// Page 3
const page3 = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [Query.limit(10), Query.offset(20)]
});
```

### Cursor-based (efficient for large datasets)

Use `cursorAfter` or `cursorBefore` for stable pagination that handles real-time data changes:

```typescript
// Get first page
const firstPage = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [Query.limit(10), Query.orderAsc('name')]
});

// Get next page using the last row's ID as cursor
const lastRow = firstPage.documents[firstPage.documents.length - 1];
const nextPage = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [Query.limit(10), Query.cursorAfter(lastRow.$id)]
});

// Get previous page
const prevPage = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [Query.limit(10), Query.cursorBefore(lastRow.$id)]
});
```

---

## Field Selection

Return only specific columns to reduce payload size:

```typescript
const selected = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [Query.select(['title', 'price', 'image'])]
});
```

---

## Complete Example

```typescript
const results = await tablesDB.listRows({
    databaseId: '[DATABASE_ID]',
    tableId: '[TABLE_ID]',
    queries: [
        // Filter: active items with price between 10 and 100
        Query.equal('status', 'active'),
        Query.between('price', 10, 100),
        // Sort: high priority first, then by title
        Query.orderDesc('priority'),
        Query.orderAsc('title'),
        // Pagination: 10 rows per page, starting at offset 20
        Query.limit(10),
        Query.offset(20),
        // Selection: only these fields
        Query.select(['title', 'price', 'priority'])
    ]
});

// Access results
console.log(`Total: ${results.total}`);
results.documents.forEach(row => {
    console.log(`${row.title}: $${row.price}`);
});
```

---

## Query Method Reference

| Method | Description |
|--------|-------------|
| `Query.equal(field, value)` | Field equals value |
| `Query.notEqual(field, value)` | Field does not equal value |
| `Query.lessThan(field, value)` | Field < value |
| `Query.lessThanEqual(field, value)` | Field Ōēż value |
| `Query.greaterThan(field, value)` | Field > value |
| `Query.greaterThanEqual(field, value)` | Field Ōēź value |
| `Query.between(field, min, max)` | min Ōēż field Ōēż max |
| `Query.isNull(field)` | Field is null |
| `Query.isNotNull(field)` | Field is not null |
| `Query.startsWith(field, prefix)` | String starts with prefix |
| `Query.endsWith(field, suffix)` | String ends with suffix |
| `Query.contains(field, substring)` | String/array contains value |
| `Query.search(field, keywords)` | Full-text search |
| `Query.orderAsc(field)` | Sort ascending |
| `Query.orderDesc(field)` | Sort descending |
| `Query.limit(n)` | Max rows returned (max 100) |
| `Query.offset(n)` | Skip N rows |
| `Query.cursorAfter(id)` | Start after row ID |
| `Query.cursorBefore(id)` | End before row ID |
| `Query.select(fields)` | Return only specified fields |
| `Query.or(queries)` | OR condition |
| `Query.and(queries)` | AND condition |

# Appwrite Function: Personalized Greeting

Here's a Node.js Appwrite Function that receives a JSON body with a `name` field and returns a personalized greeting:

```javascript
// src/main.js
export default async ({ req, res, log, error }) => {
    // Parse the JSON body
    const data = req.bodyJson;

    // Validate that name field exists
    if (!data?.name) {
        error('Missing required "name" field');
        return res.json(
            { error: 'Name field is required' },
            400
        );
    }

    const name = data.name.trim();

    // Validate name is not empty after trimming
    if (!name) {
        error('Name cannot be empty');
        return res.json(
            { error: 'Name cannot be empty' },
            400
        );
    }

    // Log the greeting for debugging
    log(`Creating greeting for: ${name}`);

    // Return the personalized greeting
    return res.json({
        success: true,
        greeting: `Hello, ${name}! Welcome to our service.`,
        name: name,
        timestamp: new Date().toISOString()
    });
};
```

## How It Works

| Component | Description |
|-----------|-------------|
| `req.bodyJson` | Parses the incoming JSON body into an object |
| `req.method` | Check the HTTP method (GET, POST, etc.) |
| `res.json(data, status)` | Returns a JSON response with optional status code |
| `log()` | Logs information for debugging |
| `error()` | Logs error information |

## Example Requests

### Request (POST with JSON body)
```json
{
    "name": "Alice"
}
```

### Response
```json
{
    "success": true,
    "greeting": "Hello, Alice! Welcome to our service.",
    "name": "Alice",
    "timestamp": "2025-01-15T10:30:00.000Z"
}
```

### Error Response (missing name)
```json
{
    "error": "Name field is required"
}
```

## Deployment Notes

1. Set the **Entrypoint** to `src/main.js` (or `src/main.ts` if using TypeScript)
2. The function uses the **Node.js 18+** runtime
3. No external dependencies are required for this simple function

Here's a complete example using the Appwrite Web SDK to create a bucket, upload a file, and get a preview URL with proper permissions.

```typescript
import { Client, Storage, ID, Permission, Role } from 'appwrite';

// Initialize client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')  // Replace with your region
    .setProject('your-project-id');

// Initialize Storage service
const storage = new Storage(client);

// ============================================
// 1. CREATE A BUCKET WITH PERMISSIONS
// ============================================
async function createBucket() {
    const bucket = await storage.createBucket({
        bucketId: ID.unique(),
        name: 'my-images-bucket',
        permissions: [
            // Allow any user to read files (public read)
            Permission.read(Role.any()),
            // Only authenticated users can create/upload files
            Permission.create(Role.users()),
            // Only file owners can update or delete their files
            Permission.update(Role.users()),
            Permission.delete(Role.users()),
        ],
        // Optional settings
        enabled: true,                    // Bucket is active
        maximumFileSize: 10485760,        // 10 MB max file size
        allowedFileExtensions: ['jpg', 'jpeg', 'png', 'gif', 'webp'],
    });

    console.log('Bucket created:', bucket.$id);
    return bucket;
}

// ============================================
// 2. UPLOAD A FILE WITH PERMISSIONS
// ============================================
async function uploadFile(bucketId: string, fileInput: HTMLInputElement) {
    const file = fileInput.files?.[0];
    if (!file) throw new Error('No file selected');

    const uploadedFile = await storage.createFile({
        bucketId: bucketId,
        fileId: ID.unique(),
        file: file,  // Pass the File object from input
        permissions: [
            // Anyone can view/download the file
            Permission.read(Role.any()),
            // Only the uploading user can modify/delete
            Permission.update(Role.user('[USER_ID]')),   // Replace with actual user ID
            Permission.delete(Role.user('[USER_ID]')),
        ],
    });

    console.log('File uploaded:', uploadedFile.$id);
    return uploadedFile;
}

// ============================================
// 3. GET IMAGE PREVIEW URL
// ============================================
async function getImagePreview(bucketId: string, fileId: string) {
    // getFilePreview returns a URL pointing to the image
    const previewUrl = storage.getFilePreview({
        bucketId: bucketId,
        fileId: fileId,
        // Optional: resize/transform the image
        width: 800,      // Resize to 800px width
        height: 600,      // Resize to 600px height
        quality: 85,      // JPEG quality (1-100)
        gravity: 'center', // Crop from center
    });

    console.log('Preview URL:', previewUrl.toString());
    return previewUrl.toString();
}

// ============================================
// PUTTING IT ALL TOGETHER
// ============================================
async function main() {
    try {
        // Step 1: Create bucket
        const bucket = await createBucket();
        console.log('Created bucket:', bucket.$id);

        // Step 2: Upload file (assuming user is logged in)
        // In a real app, you would get the file from an <input type="file">
        const fileInput = document.getElementById('file-input') as HTMLInputElement;
        const uploadedFile = await uploadFile(bucket.$id, fileInput);
        console.log('Uploaded file ID:', uploadedFile.$id);

        // Step 3: Get preview URL
        const previewUrl = await getImagePreview(bucket.$id, uploadedFile.$id);

        // Display the image
        const img = document.createElement('img');
        img.src = previewUrl;
        document.body.appendChild(img);

        console.log('Success! Preview URL:', previewUrl);
    } catch (error) {
        console.error('Error:', error);
    }
}

// ============================================
// EXAMPLE HTML FOR FILE INPUT
// ============================================
/*
<!DOCTYPE html>
<html>
<head><title>Image Upload</title></head>
<body>
    <h1>Upload Image</h1>
    <input type="file" id="file-input" accept="image/*" />
    <button onclick="main()">Upload & Preview</button>
    <div id="result"></div>

    <script type="module">
        // Paste the JavaScript code above here
    </script>
</body>
</html>
*/

// ============================================
// SERVER-SIDE ALTERNATIVE (Node.js)
// ============================================
/*
import { Client, Storage, ID, Permission, Role, InputFile } from 'node-appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject(process.env.APPWRITE_PROJECT_ID)
    .setKey(process.env.APPWRITE_API_KEY);

const storage = new Storage(client);

// Create bucket (server-side, no user context needed)
const bucket = await storage.createBucket({
    bucketId: ID.unique(),
    name: 'server-uploads',
    permissions: [
        Permission.read(Role.any()),
        Permission.create(Role.users()),
        Permission.update(Role.users()),
        Permission.delete(Role.users()),
    ],
});

// Upload file from server filesystem
const file = await storage.createFile({
    bucketId: bucket.$id,
    fileId: ID.unique(),
    file: InputFile.fromPath('/path/to/image.jpg', 'image.jpg'),
    permissions: [
        Permission.read(Role.any()),
        Permission.update(Role.user('[USER_ID]')),
        Permission.delete(Role.user('[USER_ID]')),
    ],
});

// Get preview URL
const previewUrl = storage.getFilePreview({
    bucketId: bucket.$id,
    fileId: file.$id,
    width: 400,
});
*/
```

## Key Points

| Component | Description |
|-----------|-------------|
| **Bucket permissions** | Set at bucket level to inherit defaults for all files |
| **File permissions** | Override bucket defaults per-file (optional) |
| **`Role.any()`** | Allows public access (anyone can read) |
| **`Role.users()`** | Only authenticated users can upload |
| **`Role.user(id)`** | Specific user can modify/delete their uploads |
| **`getFilePreview()`** | Returns a URL (not binary) for displaying images |

> **Security tip:** Use `Role.any()` only with `read` permissions. Avoid granting `create`, `update`, or `delete` with `Role.any()` to prevent unauthorized modifications.

# Push Notifications with Appwrite Messaging

Appwrite Messaging supports push notifications across multiple platforms. Here's what you need to know:

## Supported Providers

| Provider | Platform | Description |
|----------|----------|-------------|
| **FCM** | Android | Firebase Cloud Messaging |
| **APNS** | iOS | Apple Push Notification service |
| **Expo** | iOS/Android | For Expo-managed apps |
| **Pushwoosh** | Cross-platform | Alternative provider |

---

## Setup Steps

### 1. Configure Provider Credentials

In the **Appwrite Console** ŌåÆ **Messaging** ŌåÆ **Providers**, add your credentials:

**For FCM (Android):**
- Upload your `google-services.json` or provide the server key

**For APNS (iOS):**
- Upload your `.p12` certificate or `.p8` key
- Configure the sandbox/production endpoint

### 2. Register Devices (Client-side)

```typescript
// Web / React Native
import { Messaging } from 'appwrite';

const messaging = new Messaging(client);

// Register a device for push notifications
