    const row = await tablesDB.createRow({
        databaseId: database.$id,
        tableId: table.$id,
        rowId: ID.unique(),
        data: {
            title: 'Integrate Appwrite TablesDB',
            completed: false,
            dueDate: '2025-06-15T14:00:00.000Z'  // ISO 8601 format
