    return res.json({ error: 'Method not allowed. Use POST.' }, 405);
  }

  // req.bodyJson contains the parsed JSON body (undefined if not valid JSON)
  const data = req.bodyJson;

  // Validate the "name" field
  if (!data || typeof data.name !== 'string' || data.name.trim() === '') {
    error('Missing or invalid "name" field in request body');
    return res.json({ error: 'Missing or invalid field: name' }, 400);
  }

  const name = data.name.trim();
  log(`Generating greeting for: ${name}`);

  // Return a personalized greeting
  return res.json({
    greeting: `Hello, ${name}! ­¤æŗ Welcome to Appwrite Functions.`
  });
};
```

### Key details

| Feature | Usage |
|---------|-------|
| **Entry point** | Export a default async function with the destructured runtime context |
| **Parsed body** | `req.bodyJson` ŌĆö automatically parsed JSON (no need for `JSON.parse`) |
| **Logging** | `log()` for info-level logs; `error()` for errors (visible in execution logs) |
| **JSON response** | `res.json(object, statusCode)` ŌĆö sets `Content-Type: application/json` automatically |
| **Raw body** | `req.body` is available as the raw string if you need it |

### Example request

